import java.util.ArrayList;
import java.util.List;

class Solution {
    /**
     * Checks if a number x is a "good" integer based on the provided directions.
     * 
     * @param x The number to check.
     * @param directions The sequence of 6 directions ("D" or "R").
     * @return True if x is a good integer, false otherwise.
     */
    private static boolean isGood(long x, String directions) {
        // 1. Format x to 16 digits string
        String s = String.format("%016d", x);

        // 2. Populate Grid (4x4)
        int[][] grid = new int[4][4];
        for (int i = 0; i < 16; i++) {
            int digit = s.charAt(i) - '0';
            int r = i / 4;
            int c = i % 4;
            grid[r][c] = digit;
        }

        // 3. Traversal Path
        List<Integer> sequence = new ArrayList<>();

        // Start at (0, 0)
        int r = 0;
        int c = 0;

        // Record starting cell value
        sequence.add(grid[r][c]);

        // Apply 6 directions
        for (int i = 0; i < 6; i++) {
            char direction = directions.charAt(i);

            if (direction == 'D') {
                r += 1;
            } else if (direction == 'R') {
                c += 1;
            }

            // Record the digit at the new position
            // Since directions guarantees R and C remain within [0, 3], no explicit bounds check is needed.
            sequence.add(grid[r][c]);
        }

        // 4. Check Non-decreasing
        // Sequence length is 7. We check 6 comparisons.
        for (int i = 0; i < 6; i++) {
            if (sequence.get(i) > sequence.get(i+1)) {
                return false;
            }
        }

        return true;
    }

    public static long solve(long l, long r, String directions) {
        long count = 0;
        for (long x = l; x <= r; x++) {
            if (isGood(x, directions)) {
                count++;
            }
        }
        return count;
    }
}

