        for (int i = 0; i < 16; i++) {
            for (int j = 0; j < 2; j++) {
                for (int k = 0; k < 2; k++) {
                    Arrays.fill(memo[i][j][k], -1);
                }
            }
        }

        // Start DP: index 0, tight=true, is_zero=true, required_min=0 (since d_I0 >= 0)
        return dp(0, 1, 1, 0);
    }

    /**
