     * I_k = 4*r_k + c_k, where (r_k, c_k) is the k-th position in the path.
     */
    private static int[] calculateIndices(String directions) {
        int[] indices = new int[7];
        int r = 0; // row
        int c = 0; // column

        indices[0] = 4 * r + c; // I_0 = 0

        for (int k = 0; k < 6; k++) {
            char move = directions.charAt(k);

            if (move == 'D') {
                r += 1;
            } else if (move == 'R') {
                c += 1;
            }

            // Since 3 D's and 3 R's, we are guaranteed to stay within 4x4 grid (0..3)
            indices[k + 1] = 4 * r + c;
        }
        return indices;
    }

    /**
     * Digit DP function.
     * @param idx Current digit index being placed (0 to 15).
     * @param tight 1 if restricted by N's digits, 0 otherwise.
     * @param is_zero 1 if all digits placed so far are 0, 0 otherwise.
     * @param required_min The minimum value the next constrained digit must take.
