        long count = 0;
        int limit = tight == 1 ? (S_N.charAt(idx) - '0') : 9;

        // Check if the current index idx is one of the constrained indices P[k]
        int k = -1;
        for (int i = 0; i < 7; i++) {
            if (P[i] == idx) {
                k = i;
                break;
            }
        }

        for (int d = 0; d <= limit; d++) {

            // 1. Check constraints if current index is constrained
            if (k != -1) {
                // This digit d is d_{I_k}. It must be >= d_{I_{k-1}}, which is represented by required_min.
                if (d < required_min) {
                    continue; // Skip this digit, violates non-decreasing property
                }
            }

            // Determine new states
            int new_tight = tight & (d == limit ? 1 : 0);
            int new_is_zero = is_zero & (d == 0 ? 1 : 0);
            int new_required_min;

            // 2. Determine the required_min for the next state
            if (k != -1) {
                // We just set d_{I_k} = d. This value becomes the requirement for d_{I_{k+1}}.
                new_required_min = d;
            } else {
                // Index idx is not constrained. The requirement for the next constrained digit remains the same.
                new_required_min = required_min;
            }

            // Recurse
            count += dp(idx + 1, new_tight, new_is_zero, new_required_min);
        }

        return memo[idx][tight][is_zero][required_min] = count;
    }

    public static long solve(long l, long r, String directions) {
        // Count(R) gives count for x in [0, R]
        long countR = countGood(r, directions);

        // Count(L-1) gives count for x in [0, L-1]
        long countLMinus1 = countGood(l - 1, directions);

        // The result is Count([0, R]) - Count([0, L-1]) = Count([L, R])
        return countR - countLMinus1;
    }
}
