     */
    private static boolean isGood(long x, String directions) {
        // 1. Pad x to 16 digits
        String s = String.valueOf(x);
        String paddedS = String.format("%16s", s).replace(' ', '0');

        // 2. Fill the 4x4 grid
        int[][] grid = new int[4][4];
        for (int i = 0; i < 16; i++) {
            int digit = paddedS.charAt(i) - '0';
            int r = i / 4;
            int c = i % 4;
            grid[r][c] = digit;
        }

        // 3. Simulate path traversal
        List<Integer> sequence = new ArrayList<>();

        // Start at (0, 0)
        int r = 0;
        int c = 0;

        // Record the starting cell value
        sequence.add(grid[r][c]);

        // Apply 6 directions
        for (int i = 0; i < 6; i++) {
            char move = directions.charAt(i);

            if (move == 'D') {
                r++;
            } else if (move == 'R') {
                c++;
            }

            // Record the value at the new position
            // Since directions guarantee staying within 0..3 for both r and c, no bounds check needed.
            sequence.add(grid[r][c]);
        }

        // 4. Check the condition (non-decreasing)
        // Sequence length is 7. Check 6 comparisons.
        for (int i = 0; i < 6; i++) {
            if (sequence.get(i) > sequence.get(i+1)) {
                return false;
            }
        }

        return true;
    }

    public static long solve(long l, long r, String directions) {
        long count = 0;
        for (long x = l; x <= r; x++) {
            if (isGood(x, directions)) {
                count++;
            }
        }
        return count;
    }
}

