import java.util.Arrays;
import java.util.HashMap;
import java.util.Map;

public class Solution {

    // Memoization table: Key = (idx, is_tight, j, prev_d)
    // Since j is small (0-7) and prev_d is small (0-9), we can map the state to a long or use a custom key object.
    // Using a map for flexibility, although an array implementation would be slightly faster given the small state space.
    private static Map<String, Long> memo;
    private static char[] N_digits;
    private static int[] K; // K[j] is the index in the 16-digit sequence corresponding to S_j
    private static int sequenceLength;

    private static void precalculateK(String directions) {
        K = new int[7];
        int r = 0;
        int c = 0;

        // P_0: (0, 0)
        K[0] = 0 * 4 + 0; // Index 0 in the 16 digits

        int current_k = 1;
        for (int i = 0; i < 6; i++) {
            char d = directions.charAt(i);
            if (d == 'D') {
                r++;
            } else { // 'R'
                c++;
            }

            // P_{i+1}: (r, c)
            K[current_k] = r * 4 + c;
            current_k++;
        }
        sequenceLength = 7;
    }

    /**
     * Digit DP function to count numbers x <= N such that the sequence is non-decreasing.
     * @param idx Current digit position being placed (0 to 15).
     * @param isTight True if restricted by N's digits.
     * @param j The index of the required digit S_j we are currently filling (0 to 6). If j=7, all checks passed.
     * @param prevD The value of S_{j-1}.
     * @return The count of valid suffixes.
     */
    private static long dp(int idx, boolean isTight, int j, int prevD) {
        if (idx == 16) {
            // If we reached the end, and all 7 required digits were placed (j=7), it's a valid number.
            return j == sequenceLength ? 1 : 0;
        }

        String key = idx + "," + isTight + "," + j + "," + prevD;
        if (memo.containsKey(key)) {
            return memo.get(key);
        }

        int limit = isTight ? (N_digits[idx] - '0') : 9;
        long count = 0;

        for (int d = 0; d <= limit; d++) {
            boolean tight = isTight && (d == limit);

            int next_j = j;
            int next_prevD = prevD;
            boolean valid_transition = true;

            // Check if this position 'idx' corresponds to the next required digit S_j
            if (j < sequenceLength && idx == K[j]) {
                // We are setting S_j = d. Check condition: d >= S_{j-1}
                if (d < prevD) {
                    valid_transition = false;
                } else {
                    // Constraint satisfied. Move to check S_{j+1} next.
                    next_j = j + 1;
                    next_prevD = d;
                }
            }

            if (valid_transition) {
                count += dp(idx + 1, tight, next_j, next_prevD);
            }
        }

        memo.put(key, count);
        return count;
    }

    /**
     * Counts the number of "good" integers in the range [1, N].
     */
    private static long countGoodUpTo(long N) {
        if (N < 1) return 0;

        // 1. Convert N to 16 digits, padded with leading zeros conceptually.
        String S = Long.toString(N);
        String paddedS = String.format("%16s", S).replace(' ', '0');
        N_digits = paddedS.toCharArray();

        // 2. Initialize DP state
        memo = new HashMap<>();

        // Start DP: index 0, tight=true (limited by N), starting sequence pointer j=0, previous digit required = 0.
        // We use 0 as prevD because the smallest possible digit is 0, so 0 <= d is always true for S_0.
        long result = dp(0, true, 0, 0);

        // 3. Exclude x = 0. The DP counts 00...0 if 0 <= N.
        // The sequence for x=0 is [0, 0, 0, 0, 0, 0, 0], which is non-decreasing.
        // Since L >= 1, we must exclude 0.
        return result - 1;
    }


    public static long solve(long l, long r, String directions) {
        // Step 1: Precalculate the indices K_0, ..., K_6
        precalculateK(directions);

        // Step 2: Count good numbers up to R, and up to L-1.
        long countR = countGoodUpTo(r);
        long countLMinus1 = countGoodUpTo(l - 1);

        return countR - countLMinus1;
    }
}

